import{_ as t,c as o,o as r,ag as d}from"./chunks/framework.Bw-5EFTY.js";const u=JSON.parse('{"title":"Remote Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/agent-remote/SPEC.md","filePath":"packages/agent-remote/SPEC.md"}'),c={name:"packages/agent-remote/SPEC.md"};function s(a,e,i,n,l,p){return r(),o("div",null,e[0]||(e[0]=[d('<h1 id="remote-specification" tabindex="-1">Remote Specification <a class="header-anchor" href="#remote-specification" aria-label="Permalink to &quot;Remote Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>Owns the remote execution system for Robota SDK. Provides client-side <code>RemoteExecutor</code> (implements <code>IExecutor</code>) for proxying AI provider calls to a remote server, server-side <code>RemoteServer</code> for hosting provider endpoints, HTTP/WebSocket transport layers, and shared message/transport type contracts. Dual-export: browser entry (<code>RemoteExecutor</code>, client utilities) and server entry (<code>RemoteServer</code>).</p><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li>Does not own core agent/provider contracts (<code>IExecutor</code>, <code>IAIProvider</code>, <code>IAssistantMessage</code>); imports from <code>@robota-sdk/agent-core</code>.</li><li>Does not own application-level server composition; that belongs to <code>apps/agent-server</code> and <code>@robota-sdk/agent-remote-server-core</code>.</li><li>Keeps transport-specific behavior (HTTP, WebSocket) isolated behind the <code>ITransport</code> interface.</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>Two entry points: <code>./</code> (browser/client, resolved via <code>browser.ts</code>) and <code>./server</code> (Node.js server, resolved via <code>server.ts</code>).</p><p><strong>Client side</strong>: <code>SimpleRemoteExecutor</code> composes <code>HttpClient</code> for HTTP communication, validates requests, and maps responses to <code>IAssistantMessage</code>/<code>TUniversalMessage</code>. Supports both chat and streaming execution.</p><p><strong>Server side</strong>: <code>RemoteServer</code> creates an Express router with <code>/health</code>, <code>/providers</code>, <code>/chat</code>, <code>/stream</code>, and <code>/providers/:provider/capabilities</code> endpoints. Delegates to registered <code>IAIProvider</code> instances.</p><p><strong>Transport layer</strong>: <code>ITransport</code> interface with <code>HttpTransport</code> (internal) and <code>SimpleWebSocketTransport</code> implementations. <code>TransportError</code> provides structured transport-level errors. <code>HttpTransport</code> is used internally and is not exported from the public entry point.</p><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>This package is SSOT for the following types. Types marked <strong>public</strong> are exported from the <code>.</code> or <code>./server</code> entry points; others are internal SSOT used within this package.</p><ul><li><code>IBasicMessage</code>, <code>IRequestMessage</code>, <code>IResponseMessage</code> -- message types (<strong>public</strong> from <code>.</code>).</li><li><code>IHttpRequest</code>, <code>IHttpResponse</code>, <code>IHttpError</code>, <code>THttpMethod</code> -- HTTP types (<strong>public</strong> from <code>.</code>).</li><li><code>IPlaygroundWebSocketMessage</code>, <code>TPlaygroundWebSocketMessageKind</code> -- playground WebSocket message contract (<strong>public</strong> from <code>.</code>).</li><li><code>ITransport</code>, <code>ITransportCapabilities</code>, <code>ITransportConfig</code>, <code>TransportError</code> -- transport contracts (internal).</li><li><code>ISimpleRemoteConfig</code> -- client executor configuration (internal).</li><li><code>IHttpClientConfig</code> -- HTTP client configuration (internal).</li><li><code>IRemoteServerConfig</code> -- server configuration (internal).</li><li><code>IRemoteConfig</code>, <code>IHealthStatus</code>, <code>IUserContext</code>, <code>IProviderStatus</code> -- shared configuration/status types (internal).</li><li><code>IChatRequestBody</code>, <code>IChatResponseData</code>, <code>ITransportRequest</code>, <code>ITransportResponse</code> -- transport payload shapes (internal).</li><li><code>IExtendedAssistantMessage</code>, <code>IExtendedChatExecutionRequest</code>, <code>IExtendedStreamExecutionRequest</code> -- extended request/response types (internal).</li><li><code>CommunicationProtocol</code> -- supported protocol enum (internal).</li><li><code>IEnhancedResponseMessage</code> -- enhanced message type (internal).</li></ul><p>Note: <code>src/shared/types.ts</code> re-exports some <code>@robota-sdk/agent-core</code> types as compatibility shims. These re-exports are internal plumbing and do not represent SSOT ownership.</p><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Entry</th><th>Description</th></tr></thead><tbody><tr><td><code>RemoteExecutor</code> (<code>SimpleRemoteExecutor</code>)</td><td>class</td><td><code>.</code></td><td><code>IExecutor</code> for remote AI provider calls</td></tr><tr><td><code>HttpClient</code></td><td>class</td><td><code>.</code></td><td>Low-level HTTP client</td></tr><tr><td><code>WebSocketTransport</code> (<code>SimpleWebSocketTransport</code>)</td><td>class</td><td><code>.</code></td><td>WebSocket transport implementation</td></tr><tr><td><code>toRequestMessage</code>, <code>toResponseMessage</code>, etc.</td><td>functions</td><td><code>.</code></td><td>Pure utility transformers</td></tr><tr><td><code>IBasicMessage</code>, <code>IRequestMessage</code>, <code>IResponseMessage</code>, <code>ITokenUsage</code></td><td>types</td><td><code>.</code></td><td>Message types</td></tr><tr><td><code>IHttpRequest</code>, <code>IHttpResponse</code>, <code>IHttpError</code>, <code>THttpMethod</code></td><td>types</td><td><code>.</code></td><td>HTTP types</td></tr><tr><td><code>IPlaygroundWebSocketMessage</code>, <code>TPlaygroundWebSocketMessageKind</code></td><td>types</td><td><code>.</code></td><td>Playground WebSocket types</td></tr><tr><td><code>RemoteServer</code></td><td>class</td><td><code>./server</code></td><td>Express-based provider proxy server</td></tr></tbody></table><p>Note: <code>HttpTransport</code> is not exported from the public entry point. It is used internally by the transport layer.</p><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><ul><li><code>ITransport</code> -- consumers can implement custom transport layers with <code>send</code>, <code>sendStream</code>, <code>connect</code>, <code>disconnect</code>.</li><li><code>IRemoteServerConfig.logger</code> -- inject custom <code>ILogger</code> into server.</li><li><code>ISimpleRemoteConfig.logger</code> -- inject custom <code>ILogger</code> into client executor.</li></ul><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>Error</th><th>Condition</th></tr></thead><tbody><tr><td><code>SimpleRemoteExecutor</code></td><td><code>Error(&#39;Messages array is required...&#39;)</code></td><td>Empty messages</td></tr><tr><td><code>SimpleRemoteExecutor</code></td><td><code>Error(&#39;Provider is required&#39;)</code></td><td>Missing provider</td></tr><tr><td><code>SimpleRemoteExecutor</code></td><td><code>Error(&#39;Model is required&#39;)</code></td><td>Missing model</td></tr><tr><td><code>SimpleRemoteExecutor</code></td><td><code>Error(&#39;BaseURL is required...&#39;)</code></td><td>Missing server URL</td></tr><tr><td><code>SimpleRemoteExecutor</code></td><td><code>Error(&#39;User API key is required...&#39;)</code></td><td>Missing API key</td></tr><tr><td><code>TransportError</code></td><td>structured with <code>code</code>, <code>status</code>, <code>details</code></td><td>Transport-level failures</td></tr><tr><td><code>RemoteServer</code></td><td>HTTP 400 JSON</td><td>Missing fields or unknown provider</td></tr><tr><td><code>RemoteServer</code></td><td>HTTP 500 JSON</td><td>Provider execution failure</td></tr></tbody></table><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="interface-implementations" tabindex="-1">Interface Implementations <a class="header-anchor" href="#interface-implementations" aria-label="Permalink to &quot;Interface Implementations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Interface</th><th>Implementor</th><th>Kind</th><th>Location</th></tr></thead><tbody><tr><td><code>IExecutor</code> (agents)</td><td><code>SimpleRemoteExecutor</code></td><td>production</td><td><code>src/client/remote-executor-simple.ts</code></td></tr><tr><td><code>ITransport</code></td><td><code>HttpTransport</code></td><td>production</td><td><code>src/transport/http-transport.ts</code></td></tr><tr><td><code>ITransport</code></td><td><code>SimpleWebSocketTransport</code></td><td>production</td><td><code>src/transport/websocket-transport-simple.ts</code></td></tr></tbody></table><h3 id="inheritance-chains" tabindex="-1">Inheritance Chains <a class="header-anchor" href="#inheritance-chains" aria-label="Permalink to &quot;Inheritance Chains&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Base</th><th>Derived</th><th>Location</th><th>Notes</th></tr></thead><tbody><tr><td><code>Error</code></td><td><code>TransportError</code></td><td><code>src/transport/transport-error.ts</code></td><td>Structured transport error</td></tr></tbody></table><h3 id="cross-package-port-consumers" tabindex="-1">Cross-Package Port Consumers <a class="header-anchor" href="#cross-package-port-consumers" aria-label="Permalink to &quot;Cross-Package Port Consumers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Port (Owner)</th><th>Adapter</th><th>Location</th></tr></thead><tbody><tr><td><code>IExecutor</code> (agents)</td><td><code>SimpleRemoteExecutor</code></td><td><code>src/client/remote-executor-simple.ts</code></td></tr><tr><td><code>ILogger</code> (agents)</td><td><code>RemoteServer</code>, <code>SimpleRemoteExecutor</code></td><td><code>src/server/</code>, <code>src/client/</code></td></tr><tr><td><code>IAIProvider</code> (agents)</td><td><code>RemoteServer</code> (registers providers)</td><td><code>src/server/remote-server.ts</code></td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><ul><li><strong>Unit tests</strong>: 12 test files covering client, transport, server, shared types, and utilities: <ul><li><code>src/client/__tests__/</code>: <code>http-client.test.ts</code>, <code>http-client-chat.test.ts</code>, <code>remote-executor-simple.test.ts</code>, <code>request-handler-simple.test.ts</code></li><li><code>src/transport/__tests__/</code>: <code>http-transport.test.ts</code>, <code>websocket-transport-simple.test.ts</code>, <code>websocket-utils.test.ts</code>, <code>transport-error.test.ts</code></li><li><code>src/server/__tests__/remote-server.test.ts</code> -- RemoteServer route handling</li><li><code>src/utils/__tests__/transformers.test.ts</code> -- pure utility function tests</li><li><code>src/shared/__tests__/types.test.ts</code> -- shared type validation</li><li><code>src/__tests__/exports.test.ts</code> -- public entry point exports</li></ul></li><li><strong>Coverage gaps</strong>: Streaming paths have limited coverage.</li></ul>',30)]))}const m=t(c,[["render",s]]);export{u as __pageData,m as default};
